const fs = require("fs");
const path = require("path");
const Plugin = require("./../src/models/plugin");
const { safePath } = require("./../src/safe-path");

class ListFiles extends Plugin {
  name() {
    return "List Files";
  }

  description() {
    return "List files and folders in a directory. Returns an array of objects with name, type and full path.";
  }

  icon() {
    return "📂";
  }

  iconBase64() {
    return "data:image/png;base64,";
  }

  tags() {
    return ["io"];
  }

  paramsDefinition() {
    return [
      {
        name: "Directory Path",
        alias: "directory_path",
        type: "string",
        default: "/data",
        value: undefined,
      },
    ];
  }

  async logic(params = {}) {
    const dirPath =
      params.directory_path || (params.input && params.input.directory_path) || "/data";

    let resolvedPath;
    try {
      resolvedPath = safePath(dirPath);
    } catch (err) {
      return { status: { error: true, message: err.message }, output: {} };
    }

    try {
      if (!fs.existsSync(resolvedPath)) {
        return {
          status: { error: true, message: `Directory not found: ${resolvedPath}` },
          output: {},
        };
      }

      const stat = fs.statSync(resolvedPath);
      if (!stat.isDirectory()) {
        return {
          status: { error: true, message: `Path is not a directory: ${resolvedPath}` },
          output: {},
        };
      }

      const entries = fs.readdirSync(resolvedPath);
      const items = entries.map((entry) => {
        const fullPath = path.join(resolvedPath, entry);
        const entryStat = fs.statSync(fullPath);
        return {
          name: entry,
          type: entryStat.isDirectory() ? "directory" : "file",
          path: fullPath,
        };
      });

      return {
        status: { error: false, message: `Listed ${items.length} items` },
        output: { items },
      };
    } catch (err) {
      return {
        status: { error: true, message: err.message },
        output: {},
      };
    }
  }
}

module.exports = ListFiles;
